        LD A,E                           ; $0290  7B
        AND $0E                          ; $0291  E6 0E      ; [AI] isolate unit bits
        ADD A,A                          ; $0293  87
        ADD A,A                          ; $0294  87
        ADD A,A                          ; $0295  87         ; [AI] *8
        SUB $61                          ; $0296  D6 61
        CPL                              ; $0298  2F
        LD (DSK_SLOT),A                     ; $0299  32 E6 F3   ; [AI] unit-select value for the 6502 driver
        RET                              ; $029C  C9
; [AI] Arm the A$VEC 6502-call vector with the embedded driver's run-address $14AE
; [AI] [DOC S&HD 2-25; facts sec.4.2], then DISPATCH to the 6502 and examine the status
; [AI] byte it returns. The dispatch is the self-modified write at $02A3: its operand is
; [AI] the Z$CPU word cached at MAIN ($0103), so it writes through the SoftCard address
; [AI] -- "a write to the SoftCard address switches CPUs" [DOC S&HD 2-25; facts sec.4.3]
; [AI] -- handing control to the 6502 routine just armed in A$VEC. On return DSK_STATUS = 0
; [AI] OK; $10 = write-protected; anything else = generic I/O error. [RE]
CHECK_6502_STATUS:
        LD HL,$14AE                      ; $029D  21 AE 14   ; [AI] run-address of the embedded 6502 driver (see COPY_6502 / INCBIN below)
        LD (A_VEC),HL                    ; $02A0  22 D0 F3   ; [AI] arm A$VEC with the driver address [DOC S&HD 2-25; facts sec.4.2]
CHECK_6502_STATUS_PATCH:
        LD (WBOOT_VEC),A                 ; $02A3  32 00 00   ; [AI] CPU-SWITCH dispatch: operand = cached Z$CPU (patched at $0103); this write runs the 6502 (entry $02A4 = +1)
        LD A,(DSK_STATUS)                     ; $02A6  3A EA F3   ; [AI] 6502 result/status byte returned by the call
        OR A                             ; $02A9  B7         ; [AI] 0 = success?
        RET Z                            ; $02AA  C8         ; [AI] OK -> continue
        PUSH AF                          ; $02AB  F5
        CALL HOME_CLEAR                  ; $02AC  CD 42 02
        POP AF                           ; $02AF  F1
        LD DE,MSG_DISK_IO_ERROR          ; $02B0  11 DF 03   ; [AI] default = "Disk I/O Error$"
        CP $10                           ; $02B3  FE 10      ; [AI] write-protected status?
        JR NZ,STATUS_PRINT               ; $02B5  20 03
        LD DE,MSG_WRITE_PROTECTED        ; $02B7  11 66 03   ; [AI] "Disk Write Protected$"
STATUS_PRINT:
        JP ASK_ANOTHER                   ; $02BA  C3 B8 01   ; [AI] print error, then ask to retry/another
; [AI] Print the '$'-string at DE, then wait for the operator to press RETURN.
PRINT_AND_WAIT_CR:
        CALL PRINT_STRING                ; $02BD  CD 45 02
PRINT_AND_WAIT_CR_1:
        CALL CONIN_UPPER                 ; $02C0  CD C8 02   ; [AI] read a key
        CP $0D                           ; $02C3  FE 0D      ; [AI] RETURN?
        JR NZ,PRINT_AND_WAIT_CR_1        ; $02C5  20 F9      ; [AI] ignore everything until RETURN
        RET                              ; $02C7  C9
; [AI] Read one console character via Direct Console I/O (BDOS fn 6) [DOC CPMREF 3-44;
; [AI] facts sec.5], spin until a key is ready, abort to warm boot on ^C ($03), and
; [AI] uppercase the result.
CONIN_UPPER:
        LD E,$FF                         ; $02C8  1E FF      ; [AI] fn 6 "input" request code
        LD C,$06                         ; $02CA  0E 06      ; [AI] BDOS fn 6 = Direct Console I/O
        CALL BDOS_VEC                    ; $02CC  CD 05 00
        OR A                             ; $02CF  B7         ; [AI] no key ready?
CONIN_UPPER_1:
        JR Z,CONIN_UPPER                 ; $02D0  28 F6      ; [AI] poll until a key arrives
        CP $03                           ; $02D2  FE 03      ; [AI] ^C abort?
        JP Z,WBOOT_VEC                   ; $02D4  CA 00 00   ; [AI] ^C -> warm boot
        CP $60                           ; $02D7  FE 60      ; [AI] lowercase letter?
        RET C                            ; $02D9  D8         ; [AI] no -> return as-is
        SUB $20                          ; $02DA  D6 20      ; [AI] fold to uppercase
        RET                              ; $02DC  C9
        DEFB    $23                                              ; $02DD ; [AI] padding byte before the RAM variables
; [AI] ===== RAM variables (initialised data within the loaded image) =====
SRC_DST_DRIVES:
        DEFB    $00                                              ; $02DE ; [AI] source drive number (low byte of {dst,src})
DST_DRIVE:
        DEFB    $00                                              ; $02DF ; [AI] destination drive number (high byte)
TRACKS_TO_COPY:
        DEFB    $00                                              ; $02E0 ; [AI] tracks to copy per pass (TPA top - 7 pages)
SINGLE_DRIVE_FLAG:
        DEFB    $00                                              ; $02E1 ; [AI] 0 = read phase / multi-drive, 1 = write phase
RESUME_VECTOR:
        DEFS    30, $00    ; $02E2  fill                          ; [AI] word: copy-pass resume target ($0030 sentinel = single drive) + scratch/stack
; [AI] Stack grows down from $0300; the banner / message strings begin here and SP is
; [AI] set to $0300 so the strings sit just below the runtime stack.
STACK_TOP:
        DEFB    "      APPLE ][ CP/M"    ; $0300  string
        DEFB    $0D    ; $0313  terminator
        DEFB    $0A                                              ; $0314 ; [AI] LF
        DEFB    "16 Sector Disk Copy Program"    ; $0315  string
        DEFB    $0D    ; $0330  terminator
        DEFB    $0A                                              ; $0331 ; [AI] LF
        DEFB    "    (C) 1980 Microsoft"    ; $0332  string
        DEFB    $0D    ; $0348  terminator
        DEFB    $0A,$0D,$0A,$24                                  ; $0349 ; [AI] LF CR LF '$'
MSG_COMMAND_ERROR:
        DEFB    "Command Error$"    ; $034D  string
MSG_COPYING:
        DEFB    "Copying...$"    ; $035B  string
MSG_WRITE_PROTECTED:
        DEFB    "Disk Write Protected$"    ; $0366  string
MSG_COPY_COMPLETE:
        DEFB    "COPY Complete$"    ; $037B  string
MSG_ANOTHER_COPY:
        DEFB    "Do you wish to make another copy? $"    ; $0389  string
PROMPT_INSERT_SYSTEM:
        DEFB    "Insert CP/M System disk into drive A:"    ; $03AC  string
        DEFB    $0D    ; $03D1  terminator
        DEFB    $0A                                              ; $03D2 ; [AI] LF
        DEFB    "Hit RETURN $"    ; $03D3  string
MSG_DISK_IO_ERROR:
        DEFB    "Disk I/O Error$"    ; $03DF  string
MSG_INVALID_DRIVE:
        DEFB    "Invalid Drive$"    ; $03EE  string
PROMPT_INSERT_MASTER:
        DEFB    "Insert MASTER disk into drive "    ; $03FC  string
PROMPT_MASTER_DRV:
        ; [AI] 'Z' at $041A is patched to the dst drive letter (LD (PROMPT_MASTER_DRV),A at $014E)
        DEFB    "Z:"    ; $041A  string ($041A 'Z' patched at runtime)
        DEFB    $0D    ; $041C  terminator
        DEFB    $0A                                              ; $041D ; [AI] LF
        DEFB    "Insert SLAVE  disk into drive "    ; $041E  string
PROMPT_SLAVE_DRV:
        ; [AI] 'Z' at $043C is patched to the dst drive letter (LD (PROMPT_SLAVE_DRV),A at $013C)
        DEFB    "Z:"    ; $043C  string ($043C 'Z' patched at runtime)
        DEFB    $0D    ; $043E  terminator
        DEFB    $0A                                              ; $043F ; [AI] LF
        DEFB    $0D    ; $0440  terminator
        DEFB    $0A                                              ; $0441 ; [AI] LF
        DEFB    "Press RETURN to begin $"    ; $0442  string
MSG_CRLF_CRLF:
        DEFB    $0D    ; $0459  terminator
        DEFB    $0A,$0D,$0A,$24                                  ; $045A ; [AI] LF CR LF '$' ("\r\n\r\n$")
MSG_INSERT_MASTER2:
        DEFB    $0D,$0A,$0D    ; $045E  terminator
        DEFB    $0A                                              ; $0461 ; [AI] CR LF CR LF ("\r\n\r\n" lead-in)
        DEFB    "Insert MASTER disk and press RETURN $"    ; $0462  string
MSG_INSERT_SLAVE2:
        DEFB    $0D    ; $0487  terminator
        DEFB    $0A                                              ; $0488 ; [AI] LF ("\r\n" lead-in)
        DEFB    "Insert SLAVE  disk and press RETURN $"    ; $0489  string
; -- embedded 6502 region $04AE-$04FF: COPY's per-disk track-copy driver --
; Genuine 6502 machine code (COPY runs on the Z-80; the SoftCard runs THIS on the
; 6502). Disassembled as real 6502 in COPY_6502.s (ca65) and INCBIN'd here
; byte-for-byte. The block is RELOCATED +$1000 to run at $14AE-$14FF: COPY's Z-80
; side does LD HL,$14AE / LD (A_VEC),HL (the SoftCard A$VEC handoff cell) before
; ringing the $F000 doorbell (LD ($F000),A at $0239), so $14AE is its only entry.
; It drives the SoftCard's inner read/write-track engine (JSR $0E03) once per
; sector. The Z-80 only refers to the block by the IMMEDIATE run-address $14AE
; (a literal, not a file symbol), so no cross-CPU EQU is needed. See COPY_6502.s
; for the routine map + the trailing non-code data tail ($14DD-$14FF).
COPY_6502:
        INCBIN  "COPY_6502.bin"          ; $04AE-$04FF  (82 bytes of 6502, runs at $14AE)

    SAVEBIN "COPY.bin", $0100, $0400
